(16795, 2445, 0, NULL, '(ა) ჰიდროიზოლაცია ისე უნდა მოეწყოს, რომ ნესტმა კედელში ვერ შეაღწიოს ან არ გადავიდეს გარე მხარეს. ჰიდროიზოლაცია უნდა მოეწყოს გარე კარისა და ფანჯრის ანაწყობების, გაყვანილობების და გარე კედლის ანაწყობების დასრულების ადგილების პერიმეტრებთან, გარე კედლისა და სახურავის გადაკვეთასთან', '2025-07-11 03:07:48', '2025-07-11 03:07:48'),
(16796, 2445, 0, NULL, '(ბ) ჰიდროიზოლაცია ისე უნდა მოეწყოს, რომ ნესტმა კედელში ვერ შეაღწიოს ან არ გადავიდეს გარე მხარეს. ჰიდროიზოლაცია უნდა მოეწყოს საკვამურებთან, პორტიკებთან (კართანებთან), ტერასებთან (ბანებთან), აივნებთან და მსგავს ნაშვერებთან შეერთების ადგილებში, ასევე, ჩაშენებულ წყალსადინარ ღარებში და მსგავს ადგილებში, საიდანაც წყალმა შეიძლება კედელში შეაღწიოს', '2025-07-11 03:07:48', '2025-07-11 03:07:48'),
(16797, 2445, 0, NULL, '(გ) ჰიდროიზოლაცია ისე უნდა მოეწყოს, რომ ნესტმა კედელში ვერ შეაღწიოს ან არ გადავიდეს გარე მხარეს. ჰიდროიზოლაცია უნდა მოეწყოს გამოშვერილი კიდეების ორივე მხარეზე და ბოლოებთან კედლისზედა ბურულების, წოლანების ქვეშ  და უწყვეტი გამოშვერილი გაფორმების თავზე', '2025-07-11 03:07:48', '2025-07-11 03:07:48'),
