(2194, NULL, 'რომელია იმ პუნქტებიდან ერთ-ერთი მოთხოვნა, რომლის შემთხვევაში დასაშვებია აღიარებული, სიაში შეტანილი, გასვლის შემაფერხებელი საკეტების დაყენება დაკავებულობის ნებისმიერ კარებზე, გარდა თვ, სგ და დსშ ჯგუფის დაკავებულობებისა ისეთ შენობებში, რომლებიც მთლიანად აღჭურვილია 903.3.1.1 ქვეთავის შესაბამისად დაყენებული ავტოსაშხეფი სისტემით, 907-ე ქვეთავის შესაბამისად დაყენებული კვამლის ავტომატური აღმომჩენი ან სითბოს აღმომჩენი სისტემებით?', NULL, '2025-02-09 17:00:46', '2025-07-10 07:47:41'),
(2197, NULL, 'თვ-2, თვ-3, თვ-4, სქ, სგ, სმ, დწ-2, დწ-3, სვ და სწ ჯგუფების დაკავებულობებში, გამოსასწორებელი დაწესებულებებისა და წინასწარი დაკავების ადგილების საზღვრებში, გასასვლელი საშუალებების კარები, რომლებიც ემსახურება ოთახებს ან სივრცეებს, გამოყენებულს იმ პირთა მიერ, რომელთა მოძრაობა კონტროლდება უსაფრთხოების მიზნით, დასაშვებია ჩაიკეტოს, როდესაც აღჭურვილია გასასვლელის საკონტროლო მექანიზმით, რომელიც უნდა იღებოდეს ხელით და, სულ მცირე, ქვემოთ ჩამოთვლილი ერთ-ერთი საშუალებით:', NULL, '2025-02-09 17:04:15', '2025-07-10 07:48:35'),
(2198, NULL, 'მოცემული ვარიანტებიდან რომელია ერთ-ერთი მართებული პირობა, რომლის შემთხვევაშიც დასაშვებია გასასვლელის სპეციალური საკეტი მოწყობილობები დწ-2 ჯგუფის ისეთ დაკავებულობებში, სადაც შენობა მთლიანადაა აღჭურვილი 903.3.1.1 ქვეთავის შესაბამისი ავტოსაშხეფი სისტემით ან 907-ე ქვეთავის შესაბამისად დაყენებული კვამლის ან სითბოს ავტომატური აღმომჩენი სისტემით?', NULL, '2025-02-09 17:06:01', '2025-07-10 07:49:26'),
