INSERT INTO `regulations` (`id`, `name`, `description`, `link`, `date_applied`, `created_at`, `updated_at`) VALUES
(1, 'მშენებლობის ნებართვის გაცემისა და შენობა-ნაგებობის ექსპლუატაციაში მიღების წესი', 'საქართველოს მთავრობის 2019 წლის 31 მაისის №255 დადგენილება მშენებლობის ნებართვის გაცემისა და შენობა-ნაგებობის ექსპლუატაციაში მიღების წესისა და პირობების შესახებ', 'https://matsne.gov.ge/ka/document/view/4578072?publication=0', '2019-05-31', '2025-05-04 13:34:33', '2025-05-04 13:34:33'),
(2, 'ტერიტორიების გამოყენების და განაშენიანების რეგულირების ძირითადი დებულებები', 'საქართველოს მთავრობის 2019 წლის 3 ივნისის №261 დადგენილება ტერიტორიების გამოყენების და განაშენიანების რეგულირების ძირითადი დებულებების შესახებ', 'https://matsne.gov.ge/ka/document/view/4579383?publication=0', '2019-06-03', '2025-05-04 13:34:33', '2025-05-04 13:34:33'),
(3, 'კანონი არქიტექტურული საქმიანობის შესახებ', 'საქართველოს კანონი, რომელიც არეგულირებს არქიტექტურულ საქმიანობას', 'https://faolex.fao.org/docs/pdf/geo200047GEO.pdf', NULL, '2025-05-04 13:34:33', '2025-05-04 13:34:33'),
(4, 'საქართველოს სივრცის დაგეგმარების, არქიტექტურული და სამშენებლო საქმიანობის კოდექსი', 'კოდექსი, რომელიც არეგულირებს სივრცის დაგეგმარების, არქიტექტურული და სამშენებლო საქმიანობის სფეროებს', 'https://matsne.gov.ge/ka/document/download/4276845/16/ge/pdf', NULL, '2025-05-04 13:34:33', '2025-05-04 13:34:33'),
(5, 'ტექნიკური რეგლამენტი - შენობა-ნაგებობის უსაფრთხოების წესები', 'საქართველოს მთავრობის 2016 წლის 28 იანვრის №41 დადგენილება ტექნიკური რეგლამენტის შენობა-ნაგებობის უსაფრთხოების წესების დამტკიცების თაობაზე', 'https://www.matsne.gov.ge/ka/document/view/3176389?publication=0', '2016-01-28', '2025-05-04 13:34:33', '2025-05-04 13:34:33'),
(6, 'მისაწვდომობის ეროვნული სტანდარტები', 'საქართველოს მთავრობის 2020 წლის 4 დეკემბრის №732 დადგენილება ტექნიკური რეგლამენტის – მისაწვდომობის ეროვნული სტანდარტების დამტკიცების თაობაზე', 'https://www.rtc.edu.ge/files/%E1%83%A1%E1%83%90%E1%83%A5%E1%83%90%E1%83%A0%E1%83%97%E1%83%95%E1%83%94%E1%83%9A%E1%83%9D%E1%83%A1%20%E1%83%9B%E1%83%97%E1%83%90%E1%83%95%E1%83%A0%E1%83%9D%E1%83%91%E1%83%98%E1%83%A1%20732-%E1%83%94%20%E1%83%93%E1%83%90%E1%83%93%E1%83%92%E1%83%94%E1%83%9C%E1%83%98%E1%83%9A%E1%83%94%E1%83%91%E1%83%90.pdf', '2020-12-04', '2025-05-04 13:34:33', '2025-05-04 13:34:33');
