(7, 1, 1, 'დაკავებულობის ზოგადი მიმოხილვა', 2, 'თავი 3 - ის ძირითადი შინაარსი და დაკავებულობის ჯგუფში კლასიფიცირების წესები.', 461, 0, 'e48bafd2-e081-4784-85fe-6740483b4b7b', '382670', NULL, 'https://video.bunnycdn.com/library/382670/videos/e48bafd2-e081-4784-85fe-6740483b4b7b', NULL, '2025-04-27 11:54:39', '2025-08-11 18:45:57'),
(8, 1, 1, 'თავშეყრის ჯგუფი', 3, 'თავშეყრის ჯგუფი - რესტორანი, კაფე, სპორტული დარბაზი, სტადიონი, სალექციო დარბაზი, თეატრები, კინოთეატრები და სხვა დაკავებულობების აღწერა', 772, 0, '7424bb51-8e56-46f4-ad35-f3a72a47e4cf', '382670', NULL, 'https://video.bunnycdn.com/library/382670/videos/7424bb51-8e56-46f4-ad35-f3a72a47e4cf', NULL, '2025-04-27 11:56:03', '2025-08-11 18:45:57'),
(9, 1, 1, 'საქმიანი ჯგუფი', 4, 'საოფისე სივრცეები, ამბულატორიული კლინიკები და სხვა საქმიანი სივრცეების აღწერა.', 225, 0, '925ad24f-2df1-41ce-b39e-3a7dab699da7', '382670', NULL, 'https://video.bunnycdn.com/library/382670/videos/925ad24f-2df1-41ce-b39e-3a7dab699da7', NULL, '2025-04-27 11:57:00', '2025-08-11 18:45:57'),
